import React from 'react';
import { motion } from 'framer-motion';

const Logo: React.FC<{ size?: 'small' | 'medium' | 'large' }> = ({ size = 'medium' }) => {
  const sizeClasses = {
    small: 'w-8 h-8',
    medium: 'w-12 h-12',
    large: 'w-16 h-16'
  };

  return (
    <motion.div
      className={`relative ${sizeClasses[size]}`}
      initial={{ rotate: 0 }}
      animate={{ rotate: 360 }}
      transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
    >
      <svg viewBox="0 0 200 100" className="w-full h-full">
        {/* Modern MM Logo with architectural elements */}
        <g>
          {/* Left M with architectural lines */}
          <motion.path
            d="M20 80 L20 30 L35 55 L50 30 L50 80 M35 55 L35 80"
            stroke="#14B8A6"
            strokeWidth="4"
            fill="none"
            strokeLinecap="round"
            strokeLinejoin="round"
            initial={{ pathLength: 0, opacity: 0 }}
            animate={{ pathLength: 1, opacity: 1 }}
            transition={{ duration: 1.5, delay: 0.3, ease: "easeInOut" }}
          />
          
          {/* Right M with architectural lines */}
          <motion.path
            d="M70 80 L70 30 L85 55 L100 30 L100 80 M85 55 L85 80"
            stroke="#0891B2"
            strokeWidth="4"
            fill="none"
            strokeLinecap="round"
            strokeLinejoin="round"
            initial={{ pathLength: 0, opacity: 0 }}
            animate={{ pathLength: 1, opacity: 1 }}
            transition={{ duration: 1.5, delay: 0.5, ease: "easeInOut" }}
          />
          
          {/* Spaces text */}
          <motion.text
            x="130"
            y="55"
            fontSize="18"
            fontWeight="600"
            fill="#0D9488"
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 1, delay: 0.8, ease: "easeOut" }}
          >
            Spaces
          </motion.text>
          
          {/* Architectural roof element */}
          <motion.path
            d="M10 25 L60 10 L110 25"
            stroke="#14B8A6"
            strokeWidth="2"
            fill="none"
            opacity="0.6"
            initial={{ pathLength: 0 }}
            animate={{ pathLength: 1 }}
            transition={{ duration: 2, delay: 1, ease: "easeInOut" }}
          />
        </g>
      </svg>
    </motion.div>
  );
};

export default Logo;
